const $=id=>document.getElementById(id); let currentUser=null,currentProfile=null,unsubs=[],activeLesson=null;
const authView=$('authView'), mainView=$('mainView'), authMsg=$('authMsg');
function showMsg(t){if(authMsg)authMsg.textContent=t||''} function roleName(r){return r==='teacher'?'老师':r==='parent'?'家长':'学生'} function todayKey(){return new Date().toISOString().slice(0,10)}
function getLevel(s){return s>=300?'钻石小学霸':s>=180?'黄金小学霸':s>=80?'白银小学霸':'青铜小学霸'} function nextNeed(s){return s<80?80-s:s<180?180-s:s<300?300-s:0}
function isAdmin(){return currentProfile&&['parent','teacher'].includes(currentProfile.role)}
async function logAction(text){if(!currentUser||!currentProfile)return; await addDoc(collection(db,'logs'),{text,userId:currentUser.uid,name:currentProfile.name||'用户',createdAt:serverTimestamp()})}
async function addScore(delta,reason){await updateDoc(doc(db,'users',currentUser.uid),{score:increment(delta),updatedAt:serverTimestamp()}); await logAction(`${reason}：${delta>0?'+':''}${delta} 分`)}
function switchPage(p){document.querySelectorAll('.page').forEach(e=>e.classList.toggle('active',e.id===p));document.querySelectorAll('.nav-btn').forEach(b=>b.classList.toggle('active',b.dataset.page===p))}
document.querySelectorAll('[data-auth-tab]').forEach(btn=>btn.onclick=()=>{document.querySelectorAll('[data-auth-tab]').forEach(x=>x.classList.remove('active'));btn.classList.add('active');const l=btn.dataset.authTab==='login';$('loginForm').classList.toggle('hidden',!l);$('registerForm').classList.toggle('hidden',l);showMsg('')});
document.querySelectorAll('.nav-btn').forEach(b=>b.onclick=()=>switchPage(b.dataset.page));
$('registerForm').onsubmit=async e=>{e.preventDefault();showMsg('正在注册...');try{const name=$('regName').value.trim(),role=$('regRole').value,email=$('regEmail').value.trim(),password=$('regPassword').value;if(!name)return showMsg('请输入姓名');const cred=await createUserWithEmailAndPassword(auth,email,password);await setDoc(doc(db,'users',cred.user.uid),{name,email,role,score:0,createdAt:serverTimestamp(),updatedAt:serverTimestamp()});showMsg('注册成功')}catch(err){showMsg('注册失败：'+err.message)}};
$('loginForm').onsubmit=async e=>{e.preventDefault();showMsg('正在登录...');try{await signInWithEmailAndPassword(auth,$('loginEmail').value.trim(),$('loginPassword').value);showMsg('')}catch(err){showMsg('登录失败：'+err.message)}};
$('logoutBtn').onclick=()=>signOut(auth); $('checkinBtn').onclick=async()=>{const ref=doc(db,'users',currentUser.uid,'daily',todayKey()),s=await getDoc(ref);if(s.exists()&&s.data().checkedIn)return alert('今天已经签到过了');await setDoc(ref,{checkedIn:true,doneCount:s.data()?.doneCount||0,updatedAt:serverTimestamp()},{merge:true});await addScore(5,'每日签到')};
function initSelects(){['gradeSelect','paperGrade'].forEach(id=>{$(id).innerHTML='';for(let i=1;i<=6;i++)$(id).innerHTML+=`<option value="${i}">${i}年级</option>`});['gradeSelect','subjectSelect','termSelect'].forEach(id=>$(id).onchange=renderLessons);renderLessons();}
function renderLessons(){const g=+$('gradeSelect').value,subj=$('subjectSelect').value,term=$('termSelect').value;const list=COURSE_BANK.filter(x=>x.grade===g&&x.subject===subj&&x.term===term);$('lessonList').innerHTML=list.map(x=>`<div class="item"><div><strong>${x.title}</strong><small>${x.summary}</small></div><button class="secondary" data-id="${x.id}">学习</button></div>`).join('');document.querySelectorAll('[data-id]').forEach(b=>b.onclick=()=>openLesson(b.dataset.id));}
function openLesson(id){activeLesson=COURSE_BANK.find(x=>x.id===id);$('practiceBox').innerHTML=`<h3>${activeLesson.title}</h3><p>${activeLesson.summary}</p><ul>${activeLesson.points.map(p=>`<li>${p}</li>`).join('')}</ul><div class="card"><b>原创例题</b><p>${activeLesson.example}</p></div><button id="startQuiz" class="primary">开始练习</button>`;$('startQuiz').onclick=()=>renderQuiz(activeLesson.questions);switchPage('practice');}
function renderQuiz(qs){$('practiceBox').innerHTML='<h3>同步练习</h3>'+qs.map((q,i)=>`<div class="qitem"><div><strong>${i+1}. ${q.stem}</strong><div class="answer">${q.options.map(o=>`<button data-q="${i}" data-a="${o}">${o}</button>`).join('')}</div><small id="ex${i}"></small></div></div>`).join('');document.querySelectorAll('[data-q]').forEach(btn=>btn.onclick=()=>answerQuestion(qs[+btn.dataset.q],btn.dataset.a,btn));}
async function answerQuestion(q,a,btn){const ok=a===q.answer;btn.classList.add(ok?'ok':'bad');$('ex'+[...document.querySelectorAll('[data-q]')].indexOf(btn)).textContent=(ok?'答对：':'答错：')+q.explain;if(ok){await addScore(3,'练习答对')}else{await addDoc(collection(db,'mistakes'),{userId:currentUser.uid,stem:q.stem,answer:q.answer,yourAnswer:a,explain:q.explain,createdAt:serverTimestamp()});await logAction('新增错题')}}
$('genPaperBtn').onclick=()=>{const g=+$('paperGrade').value,subj=$('paperSubject').value,type=$('paperType').value;let qs=COURSE_BANK.filter(x=>x.grade===g&&x.subject===subj).flatMap(x=>x.questions).slice(0,18);$('paperBox').innerHTML=`<h3>${g}年级${subj}${type}</h3><p>满分100分，建议时间40分钟。本卷为系统原创组卷。</p>`+qs.map((q,i)=>`<div class="qitem"><div><strong>${i+1}. ${q.stem}</strong><small>A. ${q.options[0]}　B. ${q.options[1]}　C. ${q.options[2]}　D. ${q.options[3]}</small></div><span class="pill">5分</span></div>`).join('');};
function renderMistakes(){const q=query(collection(db,'mistakes'),orderBy('createdAt','desc'),limit(50));unsubs.push(onSnapshot(q,snap=>{let h='';snap.forEach(d=>{const x=d.data();if(x.userId===currentUser.uid)h+=`<div class="qitem"><div><strong>${x.stem}</strong><small>你的答案：${x.yourAnswer}；正确答案：${x.answer}。${x.explain}</small></div><button class="secondary" data-mid="${d.id}">复习+2</button></div>`});$('mistakeList').innerHTML=h||'暂无错题';document.querySelectorAll('[data-mid]').forEach(b=>b.onclick=()=>addScore(2,'错题复习'));}))}
function renderRanking(){const q=query(collection(db,'users'),orderBy('score','desc'),limit(20));unsubs.push(onSnapshot(q,s=>{let h='',i=1;s.forEach(d=>{const x=d.data();h+=`<div class="rank-item"><strong>${i++}. ${x.name||'未命名'} <small>${roleName(x.role)}</small></strong><span class="pill">${x.score||0}分</span></div>`});$('rankList').innerHTML=h||'暂无数据';$('adminStudents').innerHTML=h||'暂无数据';}))}
function renderLogs(){const q=query(collection(db,'logs'),orderBy('createdAt','desc'),limit(50));unsubs.push(onSnapshot(q,s=>{let h='';s.forEach(d=>{const x=d.data();h+=`<div class="log-item"><b>${x.name||'用户'}</b><br>${x.text||''}</div>`});$('logList').innerHTML=h||'暂无记录';}))}
function renderDaily(){const ref=doc(db,'users',currentUser.uid,'daily',todayKey());unsubs.push(onSnapshot(ref,s=>$('todayDone').textContent=s.data()?.doneCount||0))}
function updateUI(){const s=currentProfile?.score||0;$('scoreValue').textContent=s;$('levelValue').textContent=getLevel(s);$('userLine').textContent=`${currentProfile?.name||'用户'} · ${roleName(currentProfile?.role)} · ${currentUser.email}`;const n=nextNeed(s);$('nextLevelText').textContent=n?`距离下一等级还需 ${n} 分`:'已达到最高等级';$('levelBar').style.width=Math.min(100,s/3)+'%';}
onAuthStateChanged(auth,async user=>{unsubs.forEach(f=>f());unsubs=[];currentUser=user;if(!user){authView.classList.remove('hidden');mainView.classList.add('hidden');return}let ref=doc(db,'users',user.uid),snap=await getDoc(ref);if(!snap.exists())await setDoc(ref,{name:user.email.split('@')[0],email:user.email,role:'student',score:0,createdAt:serverTimestamp()});authView.classList.add('hidden');mainView.classList.remove('hidden');unsubs.push(onSnapshot(ref,s=>{currentProfile=s.data();updateUI();}));initSelects();renderRanking();renderLogs();renderDaily();renderMistakes();});
